import{_ as s,c as a,a2 as e,o as l}from"./chunks/framework.DPuwY6B9.js";const c=JSON.parse('{"title":"环境要求","description":"","frontmatter":{},"headers":[],"relativePath":"guide/requirement.md","filePath":"zh/guide/requirement.md","lastUpdated":1732603302000}'),t={name:"guide/requirement.md"};function p(n,i,r,h,o,k){return l(),a("div",null,i[0]||(i[0]=[e(`<h1 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to &quot;环境要求&quot;">​</a></h1><p>兰空图床是使用 <a href="https://php.net" target="_blank" rel="noreferrer">PHP</a> 语言，并使用 <a href="https://laravel.com" target="_blank" rel="noreferrer">Laravel</a> 开发框架开发的一款 Web 应用程序。 使用兰空图床，需要有一个 Web 服务器。常见的 Web 服务器例如：<a href="https://lnmp.com" target="_blank" rel="noreferrer">LNMP</a>(Nginx/MySQL/PHP)、<a href="https://lnmp.org/lnmpa.html" target="_blank" rel="noreferrer">LNMPA</a>(Nginx/MySQL/PHP/Apache)，它们分别都集成了 Web 应用程序必要的组件。</p><div class="warning custom-block"><p class="custom-block-title">注意</p><p>兰空图床不支持虚拟主机搭建，您必须拥有 Web 服务器的最高控制权，而虚拟主机没有这样的条件。</p></div><h3 id="php-要求" tabindex="-1">PHP 要求 <a class="header-anchor" href="#php-要求" aria-label="Permalink to &quot;PHP 要求&quot;">​</a></h3><p>您应该确保您的 Web 服务器具有以下最低 PHP 版本和扩展：</p><ul><li>PHP 版本 &gt;= 8.2</li><li>Ctype PHP 扩展</li><li>cURL PHP 扩展</li><li>DOM PHP 扩展</li><li>Fileinfo PHP 扩展</li><li>Filter PHP 扩展</li><li>Hash PHP 扩展</li><li>Mbstring PHP 扩展</li><li>OpenSSL PHP 扩展</li><li>PCRE PHP 扩展</li><li>PDO PHP 扩展</li><li>Session PHP 扩展</li><li>Tokenizer PHP 扩展</li><li>XML PHP 扩展</li><li>Imagick PHP 拓展</li><li>Pcntl PHP 拓展</li><li>Zip PHP 拓展</li></ul><div class="warning custom-block"><p class="custom-block-title">注意</p><p>如果你使用了云服务集成面板，控制面板厂商为了极致的安全追求，会将 PHP 的部分函数禁用，这些被禁用的函数中就包含一些程序运行时必要的函数，这时候您需要找到 PHP 的配置文件，搜索 <code>disable_functions</code> 配置项，将那些函数从这个配置项中移除。</p></div><div class="info custom-block"><p class="custom-block-title">提示</p><p>通常情况下，这些拓展大部分都是已经安装并启用了的，程序安装时会检测必要的拓展是否安装，未通过检测则无法进行安装。</p></div><h3 id="数据库" tabindex="-1">数据库 <a class="header-anchor" href="#数据库" aria-label="Permalink to &quot;数据库&quot;">​</a></h3><ul><li>MariaDB 10.3+</li><li>MySQL 5.7+</li><li>PostgreSQL 10.0+（PHP 需要安装 pgsql 拓展）</li><li>SQLite 3.35.0+</li><li>SQL Server 2017+（PHP 需要安装 sqlsrv 和 pdo_sqlsrv 拓展，以及它们可能需要的任何依赖项，例如 Microsoft SQL ODBC 驱动程序）</li></ul><h2 id="服务器配置" tabindex="-1">服务器配置 <a class="header-anchor" href="#服务器配置" aria-label="Permalink to &quot;服务器配置&quot;">​</a></h2><h3 id="nginx" tabindex="-1">Nginx <a class="header-anchor" href="#nginx" aria-label="Permalink to &quot;Nginx&quot;">​</a></h3><p>我们推荐您使用 Nginx + Sqlite3 作为组合来搭建兰空图床，以实现最小化安装。当然，数据库您也可以选择市场主流的 Mysql，但最低版本要求必须为 5.7+。</p><h3 id="supervisor" tabindex="-1">Supervisor <a class="header-anchor" href="#supervisor" aria-label="Permalink to &quot;Supervisor&quot;">​</a></h3><p>兰空图床使用消息队列来异步运行程序中的耗时任务，而启动消息队列服务，需要使用 PHP 的 CLI 模式，即通过命令终端执行：<code>php artisan queue:work</code> 使其正常运作。</p><p>在生产环境中，您需要一种方法来保持您的 <code>queue:work</code> 进程运行。<code>queue:work</code> 进程可能会因各种原因停止运行，例如超过工作者超时或执行 <code>queue:restart</code> 命令。</p><p>因此，您需要配置一个进程监视器，可以检测您的 <code>queue:work</code> 进程何时退出并自动重启它们。此外，进程监视器可以让您指定希望同时运行多少个 <code>queue:work</code> 进程。</p><p>Supervisor 是 Linux 环境中常用的进程监视器，我们将在以下文档中讨论如何配置它，或者你也可以选择其他任务你熟悉的进程管理软件。在正式安装之前，我们建议你先浏览一遍该示例文档。</p><details class="details custom-block"><summary>Supervisor 安装以及配置教程(示例)</summary><h4 id="安装-supervisor" tabindex="-1">安装 Supervisor <a class="header-anchor" href="#安装-supervisor" aria-label="Permalink to &quot;安装 Supervisor&quot;">​</a></h4><p>Supervisor 是 Linux 操作系统的进程监视器，如果 <code>queue:work</code> 进程失败，它将自动重启它们。要在 Ubuntu 上安装 Supervisor，您可以使用以下命令：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt-get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> supervisor</span></span></code></pre></div><h4 id="配置-supervisor" tabindex="-1">配置 Supervisor <a class="header-anchor" href="#配置-supervisor" aria-label="Permalink to &quot;配置 Supervisor&quot;">​</a></h4><p>Supervisor 配置文件通常存储在 <code>/etc/supervisor/conf.d</code> 目录中。在此目录中，您可以创建任意数量的配置文件，指示 supervisor 如何监视您的进程。例如，让我们创建一个 <code>lsky-pro-worker.conf</code> 文件，用来启动和监视 <code>queue:work</code> 进程：</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[program:lsky-pro-worker]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">process_name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=%(program_name)s_%(process_num)02d</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">command</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=php /www/wwwroot/app.com/artisan queue:work</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">autostart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">autorestart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">stopasgroup</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">killasgroup</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">user</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=www</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">numprocs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">redirect_stderr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">stdout_logfile</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/www/wwwroot/app.com/storage/logs/worker.log</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">stopwaitsecs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=3600</span></span></code></pre></div><p>在此示例中，<code>numprocs</code> 指令将指示 Supervisor 运行一个 <code>queue:work</code> 进程，并监视所有进程，如果它们失败，则自动重启它们。您应更改配置中的 <code>command</code> 指令，以反映您所需的队列连接和工作者选项。</p><h4 id="启动-supervisor" tabindex="-1">启动 Supervisor <a class="header-anchor" href="#启动-supervisor" aria-label="Permalink to &quot;启动 Supervisor&quot;">​</a></h4><p>创建配置文件后，您可以使用以下命令更新 Supervisor 配置并启动进程：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> supervisorctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reread</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> supervisorctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> supervisorctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;lsky-pro-worker:*&quot;</span></span></code></pre></div><p>有关 Supervisor 的更多信息，请查阅 <a href="http://supervisord.org/index.html" target="_blank" rel="noreferrer">Supervisor 文档</a>。</p></details><h3 id="imagemagick" tabindex="-1">ImageMagick <a class="header-anchor" href="#imagemagick" aria-label="Permalink to &quot;ImageMagick&quot;">​</a></h3><p><a href="https://github.com/ImageMagick/ImageMagick" target="_blank" rel="noreferrer">ImageMagick</a> 是一款免费的开源软件套件，用于编辑和处理数字图像。它可用于创建、编辑、合成或转换位图图像，并支持多种文件格式，包括 JPEG、PNG、GIF、TIFF 和 PDF。</p><p>兰空图床依赖 php imagick 拓展，调用操作系统的 ImageMagick 软件实现图片编辑能力。</p><p>注意，php imagick 拓展和 ImageMagick 软件是两个东西，这两个都是必须要安装的。</p><p>ImageMagick 是一个独立的软件工具，用于在命令行操作图像（如转换格式、调整大小、添加效果等），而 php imagick 拓展是 PHP 的一个扩展库，它提供了 ImageMagick 的 PHP 接口，用于在 PHP 程序中调用 ImageMagick 的功能。</p><details class="details custom-block"><summary>ImageMagick 安装教程(示例)</summary><h4 id="检查系统是否安装-imagemagick" tabindex="-1">检查系统是否安装 imageMagick <a class="header-anchor" href="#检查系统是否安装-imagemagick" aria-label="Permalink to &quot;检查系统是否安装 imageMagick&quot;">​</a></h4><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-g24Jv" id="tab-ougBs7N" checked><label data-title="Ubuntu/Debian" for="tab-ougBs7N">Ubuntu/Debian</label><input type="radio" name="group-g24Jv" id="tab-FVTI5ns"><label data-title="CentOS/RHEL" for="tab-FVTI5ns">CentOS/RHEL</label></div><div class="blocks"><div class="language-shell vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dpkg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> imagemagick</span></span></code></pre></div><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -qa</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ImageMagick</span></span></code></pre></div></div></div><p>如果没有任何输出则表示没有安装。</p><h4 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h4><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-b6HbN" id="tab-vrGldID" checked><label data-title="Ubuntu/Debian" for="tab-vrGldID">Ubuntu/Debian</label><input type="radio" name="group-b6HbN" id="tab-OHbbUno"><label data-title="CentOS/RHEL" for="tab-OHbbUno">CentOS/RHEL</label></div><div class="blocks"><div class="language-shell vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> imagemagick</span></span></code></pre></div><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ImageMagick</span></span></code></pre></div></div></div><p>有关 imageMagick 的更多信息，请查阅 <a href="https://imagemagick.org" target="_blank" rel="noreferrer">imageMagick 文档</a>。</p></details><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>综上所述，搭建兰空图片的必要条件为：</p><ul><li>使用 Nginx 或 Apache 作为 Web 服务器</li><li>PHP 的版本和拓展必须达到要求</li><li>数据库版本必须达到要求</li><li>服务器需要安装 ImageMagick 和进程管理软件</li></ul></div>`,26)]))}const g=s(t,[["render",p]]);export{c as __pageData,g as default};
